import type { Config } from 'tailwindcss'
import { tailwindColorLiterals } from './tokens/colors'
import { screens } from './tokens/breakpoints'
import { fontFamilies, fontSizes, fontWeights } from './tokens/typography'
import { radius } from './tokens/radius'
import { boxShadows } from './tokens/shadows'
import { containerWidthsPx } from './tokens/spacing'

const { narrow, default: defaultW, wide } = containerWidthsPx

/** Tailwind `Config` uses mutable tuples; token literals are `readonly` from `as const`. */
type ThemeExtendFontSize = NonNullable<
  NonNullable<NonNullable<Config['theme']>['extend']>['fontSize']
>

export const gsMarketingUiPreset: Partial<Config> = {
  theme: {
    container: {
      center: true,
      padding: '1rem',
      screens: {
        sm: '640px',
        md: '768px',
        lg: `${defaultW}px`,
        xl: `${defaultW}px`,
        '2xl': `${defaultW}px`,
      },
    },
    extend: {
      screens,
      maxWidth: {
        'container-narrow': `${narrow}px`,
        'container-default': `${defaultW}px`,
        'container-wide': `${wide}px`,
      },
      fontFamily: {
        heading: [...fontFamilies.heading],
        body: [...fontFamilies.body],
      },
      fontSize: { ...fontSizes } as unknown as ThemeExtendFontSize,
      fontWeight: {
        ...fontWeights,
      },
      colors: {
        ...tailwindColorLiterals,
        'gs-bg': 'var(--gs-bg)',
        'gs-surface': 'var(--gs-surface)',
        foreground: 'var(--color-foreground)',
        muted: 'var(--color-muted)',
        surface: 'var(--color-surface)',
        accent: 'var(--color-accent)',
        'accent-hover': 'var(--color-accent-hover)',
      },
      borderRadius: {
        brand: radius.brand,
        pill: radius.pill,
      },
      boxShadow: {
        soft: boxShadows.soft,
        card: boxShadows.card,
        'card-hover': boxShadows.cardHover,
        sequence: boxShadows.sequence,
        handle: boxShadows.handle,
        'modal-panel': boxShadows.modalPanel,
      },
    },
  },
}

export default gsMarketingUiPreset
